mapper.select:
SELECT m.member_id, m.name, m.gender, m.birth_date, m.phone, m.email, m.address, m.district_id, d.district_name, m.join_date, m.member_type, m.status, m.reg_date FROM erp_member m LEFT JOIN erp_district d ON m.district_id = d.district_id
AND (m.name LIKE '%' || #{keyword} || '%' OR m.phone LIKE '%' || #{keyword} || '%')
ORDER BY m.reg_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT d.district_id, d.district_name, d.leader_name, d.description, d.status, COUNT(m.member_id) AS member_count FROM erp_district d LEFT JOIN erp_member m ON d.district_id = m.district_id AND m.status = 'ACTIVE'
AND d.district_name LIKE '%' || #{keyword} || '%'
GROUP BY d.district_id, d.district_name, d.leader_name, d.description, d.status ORDER BY d.district_name LIMIT #{limit} OFFSET #{offset}

SELECT c.change_id, c.member_id, m.name AS member_name, c.change_type, c.change_date, c.prev_status, c.new_status, c.reason, c.reg_date FROM erp_member_change c LEFT JOIN erp_member m ON c.member_id = m.member_id
AND m.name LIKE '%' || #{keyword} || '%'
ORDER BY c.reg_date DESC LIMIT #{limit} OFFSET #{offset}
